output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?premier ?premierLabel WHERE {
  wd:Q58683 wdt:P352 ?premier .
  ?premier wdt:P580 ?start .
  ?premier wdt:P582 ?end .
  FILTER(YEAR(?start) <= 2018 && YEAR(?end) >= 2018)
  OPTIONAL {
    ?premier rdfs:label ?premierLabel .
    FILTER(LANG(?premierLabel) = 'en')
  }
}
